// AI-how-to-fit scoring. Keeps only topics that teach the viewer one
// concrete, usable thing about an AI tool (how to use it, or the best
// tools for a task) and that collapse into a tight 30-45s YouTube Short.
// Drops off-niche noise (stocks, crypto, politics).
//
// TOP_N controls how many Short drafts get created per run. Change freely.
const TOP_N = 5;

const all = [];
for (const item of $input.all()) {
  for (const c of (item.json.candidates || [])) all.push(c);
}

// Mentions an AI tool / product
const TOOL = /(\bai\b|chatgpt|\bgpt\b|claude|gemini|grok|midjourney|sora|perplexity|notion ?ai|zapier|n8n|copilot|\bllm\b|ai agent|prompt|automation|deepseek)/i;
// Frames it as something teachable
const HOWTO = /(how to|tutorial|guide|step|use\b|using|set ?up|build|create|automate|workflow|hack|trick|\btip(s)?\b|best |top \d)/i;
// Has a concrete proof number ("7 AI tools", "in 2 minutes", "10x")
const NUM = /(\d+\s?(ai\s?)?tools?|\d+\s?%|in\s?\d+\s?(min|minute|sec|second|hour|day)|\btop\s?\d+\b|\d+x\b)/i;
// Off-niche -> hard penalty
const OFF = /(stock market|crypto|bitcoin|invest|trading|election|politic|nsfw|onlyfans)/i;

function score(c) {
  const t = (c.title || '').trim();
  const blob = (t + ' ' + (c.summary || '')).toLowerCase();
  const words = t.split(/\s+/).filter(Boolean).length;
  let s = 0;
  if (words >= 3 && words <= 16) s += 2;   // collapses into a hook line
  if (TOOL.test(blob)) s += 3;             // actually about an AI tool
  if (HOWTO.test(blob)) s += 3;            // teachable / actionable angle
  if (NUM.test(blob)) s += 2;              // has a concrete proof number
  if (words <= 12) s += 1;                 // short enough for on-screen text
  if (c.engagement > 1000) s += 1;         // already proven to travel
  if (OFF.test(blob)) s -= 5;              // off-niche -> drop
  return s;
}

const seen = new Set();
const scored = all
  .filter(c => c && c.title && c.title.length > 12)
  .map(c => ({ ...c, reel_fit: score(c) }))
  .filter(c => {
    const key = c.title.toLowerCase().slice(0, 50);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  })
  .filter(c => c.reel_fit >= 7)
  .sort((a, b) => b.reel_fit - a.reel_fit)
  .slice(0, TOP_N);

if (scored.length === 0) {
  return [{ json: { skip: true, title: 'NO_AI_TOPICS' } }];
}
return scored.map(c => ({ json: c }));

// Build a BARE Reels-tab row per surviving candidate.
//
// OpenAI is dead (quota gone), so this workflow does NOT draft the full reel
// spec here. Instead it writes the MINIMUM the builder needs and lets the
// builder self-fill everything (script, voiceover, captions, media) for free
// on its next poll. This mirrors scripts/add_reel_topics_*.py.
//
// State: Status='Ready to Run' is Workflow B's trigger word, so each row is
// claimed automatically. (The daily cap of one reel/day still applies
// downstream in publish_due_reels.py.)

const BRAND_TONE = 'Gen Z AI-native energy. Practical, fast, no hype. Teaches young people how to actually use AI tools to work faster and smarter. Bold, direct, neon-green aesthetic, zero fluff. Every video leaves the viewer with something they can use today.';

return $input.all().map(item => {
  const c = item.json;
  // Turn the raw candidate title into a clean topic string. Keep it short.
  let topic = (c.title || '').trim().replace(/\s+/g, ' ');
  // Strip common clickbait prefixes/emoji-ish noise from source titles.
  topic = topic.replace(/^[^A-Za-z0-9]+/, '').slice(0, 90).trim();

  const keyPoints = (c.summary || '').toString().slice(0, 200).trim()
    || 'Teach the viewer one concrete, usable AI trick from this topic.';

  return {
    json: {
      'Topic': topic,
      'Key Points': keyPoints,
      'Brand Tone': BRAND_TONE,
      'Enriched Context': `[auto-found] source=${c.source} fit=${c.reel_fit} ${c.url || ''}`.slice(0, 480),
      'YouTube URL': c.source === 'youtube' ? (c.url || '') : '',
      'Status': 'Ready to Run',
      'Post Type': 'reel',
      'Slide Content': 'reel',
      'Reel Fit': c.reel_fit != null ? c.reel_fit : ''
    }
  };
});

// Runs once for ALL appended rows -> builds a single summary email.
// Because the rows are written 'Ready to Run', Workflow B (the tweet-card reel
// builder) claims them automatically on its next poll -- no manual step needed.
// This email is just an FYI of what got queued.
const rows = $input.all().map(i => i.json).filter(Boolean);
const count = rows.length;
const sheetUrl = 'https://docs.google.com/spreadsheets/d/13AEU80ULx2Lxnq9SWDeSSFN7unfhr-x_mPyi37oz7O4/edit';

const list = rows
  .map((r, i) => `${i + 1}. ${r.Topic || '(untitled)'}  [fit ${r['Reel Fit'] != null ? r['Reel Fit'] : '?'}]`)
  .join('\n');

const subject = `${count} new AI reel topic${count === 1 ? '' : 's'} queued (Ready to Run)`;
const body = `The Topic Finder just added ${count} topic${count === 1 ? '' : 's'} to the Reels tab as 'Ready to Run'.\n\n${list}\n\nThe reel builder (Workflow B) will pick these up automatically on its next poll and render them (capped to one reel/day downstream). No action needed from you.\n\nReels tab:\n${sheetUrl}`;

return [{ json: { subject, body, count } }];
